SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
SET AUTOCOMMIT = 0;
START TRANSACTION;
SET time_zone = "+00:00";

CREATE TABLE `skp_lampiran` (
  `id_lampiran` int(11) NOT NULL,
  `nama` varchar(255) NOT NULL,
  `nip` char(18) NOT NULL,
  `nama_atasan_langsung` varchar(255) NOT NULL,
  `nip_atasan_langsung` char(18) NOT NULL,
  `tahun` year(4) NOT NULL,
  `kategori_lampiran` varchar(100) DEFAULT NULL,
  `isi_lampiran` text DEFAULT NULL,
  `status` varchar(100) DEFAULT NULL,
  `tanggal_input` datetime DEFAULT current_timestamp(),
  `tanggal_evaluasi_lampiran` datetime NOT NULL,
  `PANGKAT_GOL_RUANG` varchar(100) DEFAULT NULL,
  `JABATAN` varchar(100) DEFAULT NULL,
  `UNIT_KERJA` varchar(200) DEFAULT NULL,
  `SATUAN_KERJA` varchar(200) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

